+    console.log('='.repeat(70) + '\n');
+
+    await fs.mkdir(this.outputDir, { recursive: true });
+
+    this.results = [];
+
+    const modelEntries = Array.from(this.models.entries());
+    for (const [name, { lm, config }] of modelEntries) {
+      console.log(`\n📊 Benchmarking: ${name}`);
